const products = $node["Parse AI JSON"].json["order_state"].products;
const productDetails = $items("Get products").map(item => item.json);

const result = products.filter(product => !product.customized_product_name)  // Exclude customized products
  .map(product => {

  if (!product.product_name) {
    return {
      ...product,
      error: "Product name is missing"
    };
  }

  const matchedProduct = productDetails.find(p =>
    p.name && p.name.toLowerCase() === product.product_name.toLowerCase() // Ensure p.name is defined
  );

  if (!matchedProduct) {
    return {
      ...product,
      error: "Product not found"
    };
  }

  if (!product.color) {
    return {
      ...product,
      error: "Product color is missing"
    };
  }

  const variation = matchedProduct.variations.find(v =>
    v.name && v.name.toLowerCase().includes(product.color.toLowerCase()) // Ensure v.name is defined
  );

  if (!variation) {
    return {
      ...product,
      error: "Variation not found"
    };
  }

  // Create metadata for main products
  let metadata = `Color: ${product.color} | ${product.size}: ${product.quantity}`;

  const item_price = parseFloat((Number(variation.price) * Number(product.quantity)).toFixed(2));   

  return {
    sku: matchedProduct.sku || "",
    line_id: variation.id,
    product_name: product.product_name,
    qty: Number(product.quantity),
    item_price: item_price,
    original_unit_price: Number(variation.price),
    order_item_metadata: metadata // Using the metadata string here
  };

});

return {
  json: {
    products: result
  }
};

const products = $node["Parse AI JSON"].json["order_state"].products;
let productList = "";

if (products.length > 0) {
  products.forEach(product => {
    // Build the product list with only the required fields
    productList += `<li>
      <strong>Product Name:</strong> ${product.product_name}<br>
      <strong>Color:</strong> ${product.color}<br>
      <strong>Size:</strong> ${product.size}<br>
      <strong>Quantity:</strong> ${product.quantity}<br>
    </li>`;
  });
} else {
  productList = "No products found.";
}

return {
  json: {
    product_list_html: productList
  }
};

const products = $json["order_state"]["products"];
const urls = products.map(product => `https://html.yoursite.com/eww/get-product-details.php?product_name_query=${encodeURIComponent(product.product_name)}`);
return { json: { productUrls: urls } };

const productUrls = $json["productUrls"];
const requests = productUrls.map(url => {
  return {
    json: {
      url: url
    }
  };
});

return requests;

// Get products from the previous node
const products = $node["Match Product Data & store"].json.products;

let orderSubtotal = 0;
const taxRate = 0.20;  // Assuming 20% tax
const shippingCost = 7.5;

for (let i = 0; i < products.length; i++) {
  const itemPrice = Number(products[i].item_price) || 0;  // Use the item price from the products data

  // Add the product's total price (item_price) to the order subtotal
  orderSubtotal += itemPrice;
}

// Tax Calculation: 20% tax
const orderTax = orderSubtotal * taxRate;

// Total Calculation: Add tax and shipping cost
const orderTotal = orderSubtotal + orderTax + shippingCost;

return {
  json: {
    order_subtotal:parseFloat( orderSubtotal.toFixed(2)),  // Round to 2 decimal places
    order_tax: parseFloat(orderTax.toFixed(2)),  // Round to 2 decimal places
    order_total: parseFloat(orderTotal.toFixed(2)),  // Round to 2 decimal places
  }
};

const shippingAddress = $node["Parse AI JSON"].json.shipping_address || {};
const billingAddress = $node["Parse AI JSON"].json.billing_address || {};
const fullName = $node["Store Conversation"].json.conversation || "";

// NAME PARSER (If needed)
function parseName(text) {
  const match = text.match(/From:\s*(.*?)</);
  if (!match) return { first: "", last: "" };

  const name = match[1].trim().split(" ");
  return {
    first: name[0] || "",
    last: name.length > 1 ? name.slice(1).join(" ") : ""
  };
}

const name = parseName(fullName);

// Directly extract address fields from the billing and shipping address objects
const extractAddressFields = (address) => {
  return {
    street: address.street || "",
    city: address.city || "",
    state: address.state || "",
    postcode: address.postcode || "",
    country: address.country || "",
    phone:address.phone || "",
  };
};

// Extracted fields
const billingFields = extractAddressFields(billingAddress);
const shippingFields = extractAddressFields(shippingAddress);

// Returning the formatted JSON with direct extraction from address objects
return [
  {
    json: {
      billing_first_name: name.first,
      billing_last_name: name.last,
      billing_address: billingFields.street,
      billing_city: billingFields.city,
      billing_state: billingFields.state,
      billing_postcode: billingFields.postcode,
      billing_country: billingFields.country,
      billing_phone:billingFields.phone,

      shipping_first_name: name.first,
      shipping_last_name: name.last,
      shipping_address: shippingFields.street,
      shipping_city: shippingFields.city,
      shipping_state: shippingFields.state,
      shipping_postcode: shippingFields.postcode,
      shipping_country: shippingFields.country,
      shipping_phone: shippingFields.phone,
    }
  }
];

const parsed = $json.output[0].content[0].text;

// get previous order_id (from earlier node)
let previousOrderId = $node["Message a model"]?.output?.order_state?.order_id;

// preserve existing OR fallback
let orderId = parsed?.order_state?.order_id || previousOrderId;

if (!orderId) {
  orderId = 'ORD-' + Date.now();
}

parsed.order_state = parsed.order_state || {};
parsed.order_state.order_id = orderId;

return [
  {
    json: parsed
  }
];

const fullThread = $json.fullThread; 

const finalImages = $node["parse urls"].json.attachments || []; 

let thread = fullThread || "";

const messages = thread.split("\n");

// Filter out any lines starting with "On [day], [date] at [time] [email] wrote:" or those that are part of a quoted message (lines that start with '>')
const filteredMessages = messages.filter(message => {
  // Skip lines that start with "On [day], [date] at [time] [email] wrote:" or any quoted content starting with '>'
  return !message.trim().startsWith("On") && !message.trim().startsWith(">");
});

// Rebuild the cleaned thread by joining the remaining messages
const cleanedThread = filteredMessages.join("\n").trim();
return [
  {
    json: {
      conversation: cleanedThread,
      image_urls: finalImages
    }
  }
];

