// 🔹 OLD from DB
const prevRaw = $json.new_urls || "[]";

let prev = [];
try {
  prev = JSON.parse(prevRaw);
} catch (e) {
  prev = [];
}

// 🔹 SAFE access to JS4
let newUrls = [];

try {
  newUrls = $node["store urls in arr"].json.new_urls || [];
} catch (e) {
  newUrls = []; // JS4 not executed → fallback
}

// If no new attachments → keep old
if (newUrls.length === 0) {
  return [{
    json: {
      threadId:$('Loop Over Items').item.json.threadId,
      urls: JSON.stringify(prev)
    }
  }];
}

// 🔹 Merge
const merged = [
  ...prev,
  ...newUrls.filter(u => !prev.includes(u))
];

return [{
  json: {
    threadId: $('Loop Over Items').item.json.threadId,
    urls: JSON.stringify(merged)
  }
}];

const messages = $json.messages;  // Get all messages in the thread
let fullThread = ""; // Initialize empty string to build the cleaned thread

// Loop through all messages in the thread
messages.forEach(message => {
  const payload = message.payload;  // Get payload of each message

  // Extract the 'From' field from the headers
  const headers = payload.headers || [];
  let from = "";

  // Loop through headers to get 'From' and 'Subject'
  for (const h of headers) {
    if (h.name === "From") from = h.value;
  }

  // Add 'From' and 'Subject' to the thread
  fullThread += `${from}\n`;

  function decodeBase64(data) {
    return Buffer.from(data, 'base64').toString('utf-8');
  }

  // Extract and decode the body of each message (plain text)
  if (payload.parts) {
    for (const part of payload.parts) {
      if (part.mimeType === "text/plain" && part.body?.data) {
        fullThread += decodeBase64(part.body.data);
        break;  // Stop after extracting plain text part
      }
    }
  }

  // Fallback for non-multipart emails (use body data for plain text)
  if (payload.body?.data) {
    fullThread += decodeBase64(payload.body.data);
  }
});

// Return the cleaned email body (plain text)
return { fullThread };

let state = {};

try {
  state = JSON.parse($json["order_state"] || "{}");
} catch (e) {}

return [{
  json: {
    order_state: state
  }
}];

const emailBody = ($('Loop Over Items').item.json.text || "").trim();

// Filter the email body to remove quoted content like "On Thu, May 7, 2026 at ..."
const filteredMessage = emailBody.split("\n").filter(line => {
  return !line.trim().startsWith("On") && !line.trim().startsWith(">"); // Skip quoted lines
}).join("\n").trim(); // Join the filtered lines back into a single string

return [
  {
    json: {
      text: filteredMessage,
     },
  },
];
